INSERT INTO `maths_question` VALUES (1,'Find the unknown length.','multiple_choice',1,1,'Use the given measurements to find the unknown length.','questions/year5/measurements/image5.png','2025-10-28 05:47:28.003000','2026-02-14 00:02:01.087000',5,1),(23,'What is the length of the pencil?\n\n[Choose the best estimate]','multiple_choice',1,1,'A typical pencil is about 15-18 cm long.','','2025-10-28 05:53:04.272000','2025-11-07 23:11:14.998000',2,1),(24,'Which is the shortest?\n\nA) Your finger\nB) A spoon\nC) A book\nD) A door','multiple_choice',1,1,'Your finger is the shortest object among the options.','','2025-10-28 05:53:04.330000','2025-11-07 23:11:16.811000',2,1),(25,'How many centimetres are in 1 metre?','multiple_choice',1,1,'1 metre equals 100 centimetres.','','2025-10-28 05:53:04.361000','2025-11-07 23:11:16.963000',2,1),(26,'What would you use to measure the length of your desk?\n\nA) A ruler\nB) A thermometer\nC) A clock\nD) A scale','multiple_choice',1,1,'A ruler is used to measure length.','','2025-10-28 05:53:04.390000','2025-11-07 23:11:15.186000',2,1),(27,'If a pencil is 12 cm long and you cut off 4 cm, how much is left?','multiple_choice',1,1,'Subtract 4 cm from 12 cm: 12 - 4 = 8 cm.','','2025-10-28 05:53:04.419000','2025-11-07 23:11:17.266000',2,1),(28,'Which would be about 1 metre long?\n\nA) Your thumb\nB) A book\nC) Your arm span\nD) A car','multiple_choice',1,1,'Your arm span (the distance from fingertip to fingertip with arms outstretched) is approximately 1 metre for most people.','','2025-10-28 05:53:04.450000','2025-11-07 23:11:17.421000',2,1),(29,'What is the longest?\n\nA) A paperclip (3 cm)\nB) A pencil (15 cm)\nC) A pen (12 cm)\nD) A straw (20 cm)','multiple_choice',1,1,'A straw at 20 cm is the longest among the options.','','2025-10-28 05:53:04.479000','2025-11-07 23:11:17.574000',2,1),(30,'Estimate: How long is a typical toothbrush?\n\nA) 10 cm\nB) 20 cm\nC) 30 cm\nD) 40 cm','multiple_choice',1,1,'A typical toothbrush is approximately 20 cm long.','','2025-10-28 05:53:04.506000','2025-11-07 23:11:17.884000',2,1),(31,'Which measurement would you use to measure how tall your friend is?\n\nA) cm\nB) m\nC) g\nD) kg','multiple_choice',1,1,'We measure height in meters (m) or centimeters (cm). For a person\'s height, meters is more appropriate.','','2025-10-28 05:53:04.530000','2025-11-07 23:11:15.352000',2,1),(32,'A rope is 10 metres long. Another rope is 15 metres long. What is the total length?','multiple_choice',1,1,'To find the total, add: 10 + 15 = 25 metres.','','2025-10-28 05:53:04.557000','2025-11-07 23:11:15.538000',2,1),(33,'How many centimetres are in half a metre?','multiple_choice',1,1,'Half a metre is 0.5 m, which equals 50 cm.','','2025-10-28 05:53:45.593000','2025-11-07 23:12:14.441000',3,1),(34,'If you have a ribbon that is 1 metre long and you cut 30 cm off, how much is left?','multiple_choice',1,1,'1 metre = 100 cm. After cutting 30 cm: 100 - 30 = 70 cm.','','2025-10-28 05:53:45.681000','2025-11-07 23:12:14.613000',3,1),(35,'Which is the heaviest?\n\nA) A feather\nB) A book\nC) A car\nD) A ball','multiple_choice',1,1,'A car is the heaviest object among the options.','','2025-10-28 05:53:45.715000','2025-11-07 23:12:14.779000',3,1),(36,'A water bottle holds 500 ml. How many millilitres are in 1 litre?','multiple_choice',1,1,'1 litre equals 1000 millilitres.','','2025-10-28 05:53:45.741000','2025-11-07 23:12:14.943000',3,1),(37,'Estimate: How tall is a typical 8-year-old child?','multiple_choice',1,1,'A typical 8-year-old child is approximately 130 cm tall.','','2025-10-28 05:53:45.767000','2025-11-07 23:12:15.102000',3,1),(38,'Which holds the most water?\n\nA) A teaspoon (5 ml)\nB) A glass (250 ml)\nC) A jug (1000 ml)\nD) A bucket (10 litres)','multiple_choice',1,1,'A bucket holding 10 litres (10,000 ml) holds the most water.','','2025-10-28 05:53:45.799000','2025-11-07 23:12:15.263000',3,1),(39,'Which unit would you use to measure the weight of an apple?','multiple_choice',1,1,'An apple is light, so we use grams to measure its weight.','','2025-10-28 05:53:45.822000','2025-11-07 23:12:12.920000',3,1),(40,'A box is 40 cm long, 20 cm wide, and 30 cm tall. What is the approximate height?','multiple_choice',1,1,'The height is given as 30 cm in the question.','','2025-10-28 05:53:45.868000','2025-11-07 23:12:13.099000',3,1),(42,'Which is the lightest?\n\nA) An elephant\nB) A dog\nC) A pencil\nD) A car','multiple_choice',1,1,'A pencil is the lightest object among the options.','','2025-10-28 05:53:45.925000','2025-11-07 23:12:15.408000',3,1),(43,'How many millimetres are in 5 centimetres?','multiple_choice',1,1,'1 cm = 10 mm, so 5 cm = 5 × 10 = 50 mm.','','2025-10-28 05:53:45.953000','2025-11-07 23:12:15.562000',3,1),(44,'Estimate: How long would it take to walk 1 kilometre?\n\nA) 10 minutes\nB) 15 minutes\nC) 30 minutes\nD) 1 hour','multiple_choice',1,1,'It typically takes about 15 minutes to walk 1 kilometre at a normal walking pace.','','2025-10-28 05:53:45.990000','2025-11-07 23:12:15.737000',3,1),(45,'Which metric unit would be most appropriate for measuring the height of a classroom?','multiple_choice',3,2,'The height of a classroom is typically a few meters tall, so meters is the most appropriate unit.','','2025-10-28 09:40:38.044000','2025-11-07 23:13:22.165000',6,1),(46,'Which metric unit would be most appropriate for measuring the distance around the school?','multiple_choice',3,2,'The distance around a school perimeter is typically measured in kilometers.','','2025-10-28 09:40:38.079000','2025-11-07 23:13:27.467000',6,1),(47,'Which metric unit would be most appropriate for measuring the length of a pencil?','multiple_choice',3,2,'A pencil is about 15-18 cm long, so centimeters is the most appropriate unit.','','2025-10-28 09:40:38.104000','2025-11-07 23:13:22.357000',6,1),(48,'Which metric unit would be most appropriate for measuring the width of a fingernail?','multiple_choice',3,2,'A fingernail is about 1 cm wide, so millimeters would give the most precise measurement.','','2025-10-28 09:40:38.125000','2025-11-07 23:13:22.540000',6,1),(49,'Which metric unit would be most appropriate for measuring the distance between two cities?','multiple_choice',3,2,'Distances between cities are measured in kilometers.','','2025-10-28 09:40:38.147000','2025-11-07 23:13:27.656000',6,1),(50,'Which metric unit would be most appropriate for measuring the length of a ruler?','multiple_choice',3,2,'A ruler is 30 cm long, so centimeters is the appropriate unit.','','2025-10-28 09:40:38.171000','2025-11-07 23:13:22.711000',6,1),(51,'Convert 5 meters to centimeters.','multiple_choice',3,2,'1 meter = 100 centimeters, so 5 meters = 5 × 100 = 500 cm','','2025-10-28 09:40:38.193000','2025-11-07 23:13:22.904000',6,1),(52,'Convert 86000 centimeters to kilometers.','multiple_choice',3,2,'1 km = 100000 cm, so 86000 cm ÷ 100000 = 0.86 km','','2025-10-28 09:40:38.214000','2025-11-07 23:13:23.083000',6,1),(53,'Convert 6.5 meters to millimeters.','multiple_choice',3,2,'1 meter = 1000 millimeters, so 6.5 meters = 6.5 × 1000 = 6500 mm','','2025-10-28 09:40:38.237000','2025-11-07 23:13:23.253000',6,1),(54,'Convert 600000 millimeters to kilometers.','multiple_choice',3,2,'1 km = 1000000 mm, so 600000 mm ÷ 1000000 = 0.6 km','','2025-10-28 09:40:38.261000','2025-11-07 23:13:23.426000',6,1),(55,'Convert 3 kilometers to meters.','multiple_choice',3,2,'1 kilometer = 1000 meters, so 3 kilometers = 3 × 1000 = 3000 m','','2025-10-28 09:40:38.282000','2025-11-07 23:13:23.603000',6,1),(56,'Convert 450 centimeters to meters.','multiple_choice',3,2,'1 meter = 100 centimeters, so 450 cm ÷ 100 = 4.5 m','','2025-10-28 09:40:38.306000','2025-11-07 23:13:23.769000',6,1),(57,'Convert 2.8 kilometers to meters.','multiple_choice',3,2,'1 km = 1000 m, so 2.8 km = 2.8 × 1000 = 2800 m','','2025-10-28 09:40:38.326000','2025-11-07 23:13:23.935000',6,1),(58,'Convert 7500 millimeters to centimeters.','multiple_choice',3,2,'1 cm = 10 mm, so 7500 mm ÷ 10 = 750 cm','','2025-10-28 09:40:38.349000','2025-11-07 23:13:24.115000',6,1),(59,'Convert 9.3 centimeters to millimeters.','multiple_choice',3,2,'1 cm = 10 mm, so 9.3 cm × 10 = 93 mm','','2025-10-28 09:40:38.373000','2025-11-07 23:13:24.292000',6,1),(60,'Convert 1.5 meters to millimeters.','multiple_choice',3,2,'1 m = 1000 mm, so 1.5 m = 1.5 × 1000 = 1500 mm','','2025-10-28 09:40:38.395000','2025-11-07 23:13:24.489000',6,1),(79,'Which unit would you use to measure the length of a pencil?','multiple_choice',1,1,'A pencil is small, so we use centimeters to measure it.','','2025-10-29 03:29:54.592000','2025-11-07 23:11:15.703000',2,1),(81,'Which unit would you use to measure the capacity of a water bottle?','multiple_choice',1,1,'We use liters to measure how much liquid a container can hold.','','2025-10-29 03:29:54.728000','2025-11-07 23:11:16.079000',2,1),(82,'Which unit would you use to measure how tall you are?','multiple_choice',1,1,'We measure height in centimeters or meters.','','2025-10-29 03:29:54.787000','2025-11-07 23:11:16.327000',2,1),(83,'Which unit would you use to measure the weight of a toy car?','multiple_choice',1,1,'A toy car is light, so we use grams to measure its weight.','','2025-10-29 03:29:54.847000','2025-11-07 23:11:16.506000',2,1),(84,'Which unit would you use to measure the length of your bed?','multiple_choice',1,1,'A bed is big, so we use meters to measure its length.','','2025-10-29 03:29:54.901000','2025-11-07 23:11:16.657000',2,1),(85,'Convert 1m to cm','multiple_choice',1,1,'1 metre = 100 centimetres.','','2025-10-29 05:18:46.096000','2025-11-07 23:12:15.906000',3,1),(86,'Convert 2.5m to cm','multiple_choice',1,1,'2.5 metres = 2.5 × 100 = 250 centimetres.','','2025-10-29 05:18:46.163000','2025-11-07 23:12:16.067000',3,1),(87,'Convert 0.5m to cm','multiple_choice',1,1,'0.5 metres = 0.5 × 100 = 50 centimetres.','','2025-10-29 05:18:46.193000','2025-11-07 23:12:16.255000',3,1),(88,'Convert 3m to cm','multiple_choice',1,1,'3 metres = 3 × 100 = 300 centimetres.','','2025-10-29 05:18:46.226000','2025-11-07 23:12:16.500000',3,1),(89,'Convert 1.5m to cm','multiple_choice',1,1,'1.5 metres = 1.5 × 100 = 150 centimetres.','','2025-10-29 05:18:46.262000','2025-11-07 23:12:16.671000',3,1),(90,'Convert 4m to cm','multiple_choice',1,1,'4 metres = 4 × 100 = 400 centimetres.','','2025-10-29 05:18:46.296000','2025-11-07 23:12:16.873000',3,1),(91,'Convert 0.75m to cm','multiple_choice',1,1,'0.75 metres = 0.75 × 100 = 75 centimetres.','','2025-10-29 05:18:46.327000','2025-11-07 23:12:17.040000',3,1),(92,'Convert 2m to cm','multiple_choice',1,1,'2 metres = 2 × 100 = 200 centimetres.','','2025-10-29 05:18:46.360000','2025-11-07 23:12:17.211000',3,1),(93,'Convert 5m to cm','multiple_choice',1,1,'5 metres = 5 × 100 = 500 centimetres.','','2025-10-29 05:18:46.388000','2025-11-07 23:12:17.369000',3,1),(94,'Convert 0.25m to cm','multiple_choice',1,1,'0.25 metres = 0.25 × 100 = 25 centimetres.','','2025-10-29 05:18:46.421000','2025-11-07 23:12:17.530000',3,1),(100,'Which is longer and by how many millimetres: 1.24 m or 1458 mm?','multiple_choice',1,1,'Convert 1.24 m to mm: 1.24 × 1000 = 1240 mm. Compare: 1458 mm - 1240 mm = 218 mm. So 1458 mm is longer by 218 mm.','','2025-10-29 06:33:52.833000','2025-11-07 23:13:26.108000',6,1),(101,'Find the perimeter of each of these shapes.','short_answer',1,1,'Calculate the perimeter by finding the half circle\'s arc length (one-half of the full circle\'s circumference) and adding it to the two straight side lengths.','questions/year6/measurements/image13.png','2025-10-29 06:34:49.131000','2025-12-06 07:33:46.607000',6,1),(188,'Can you complete the following sequence by counting on in 1s? 1, 2, 3, 4, 5, ___ , ___ , ___ , ___ , ___','multiple_choice',1,1,'Counting forward in 1s from 5: 6, 7, 8, 9, 10','','2025-11-05 10:43:29.659000','2025-11-07 23:11:34.246000',2,14),(189,'Can you complete the following sequence by counting on in 1s? 11, 12, 13, 14, 15, ___ , ___ , ___ , ___ , ___','multiple_choic