/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `maths_studentanswer` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `text_answer` longtext NOT NULL,
  `is_correct` tinyint(1) NOT NULL,
  `points_earned` int unsigned NOT NULL,
  `answered_at` datetime(6) NOT NULL,
  `question_id` bigint NOT NULL,
  `selected_answer_id` bigint DEFAULT NULL,
  `student_id` bigint NOT NULL,
  `session_id` varchar(100) NOT NULL,
  `time_taken_seconds` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `maths_studentanswer_student_id_question_id_40a5cab9_uniq` (`student_id`,`question_id`),
  KEY `maths_studentanswer_question_id_d152e067_fk_maths_question_id` (`question_id`),
  KEY `maths_studentanswer_selected_answer_id_dfa80343_fk_maths_ans` (`selected_answer_id`),
  CONSTRAINT `maths_studentanswer_question_id_d152e067_fk_maths_question_id` FOREIGN KEY (`question_id`) REFERENCES `maths_question` (`id`),
  CONSTRAINT `maths_studentanswer_selected_answer_id_dfa80343_fk_maths_ans` FOREIGN KEY (`selected_answer_id`) REFERENCES `maths_answer` (`id`),
  CONSTRAINT `maths_studentanswer_student_id_47bfc542_fk_maths_customuser_id` FOREIGN KEY (`student_id`) REFERENCES `maths_customuser` (`id`),
  CONSTRAINT `maths_studentanswer_chk_1` CHECK ((`points_earned` >= 0)),
  CONSTRAINT `maths_studentanswer_chk_2` CHECK ((`time_taken_seconds` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=2032 DEFAULT CHARSET=utf8mb3;
